/*
# Update core_domain.sh with conditional winbind offline logon

1. Changes
- Updates `scripts` table row id=2 (core_domain.sh)
- Replaces content with corrected version (7013 bytes)
- Adds conditional WINBIND_OFFLINE variable based on AUTH_METHOD and OFFLINE_AUTH_ENABLED
- Uses ${WINBIND_OFFLINE} in smb.conf instead of hardcoded "false"
2. Notes
- Data update only, no schema changes
- Content base64-encoded to preserve exact bytes
*/

UPDATE scripts SET content = convert_from(decode('', 'base64'), 'UTF8') WHERE id = 2 AND is_core = true;